import{_ as t,o,a as n,ag as a}from"./chunks/framework.1whTfjCw.js";const u=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"tnk/concepts.md","filePath":"tnk/concepts.md","lastUpdated":1784506044000}'),s={name:"tnk/concepts.md"};function i(r,e,d,c,l,p){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><h2 id="the-three-planes" tabindex="-1">The three planes <a class="header-anchor" href="#the-three-planes" aria-label="Permalink to &quot;The three planes&quot;">​</a></h2><p>tnk manages three runtime planes, each with its own lifecycle and CLI namespace.</p><h3 id="engine-plane" tabindex="-1">Engine plane <a class="header-anchor" href="#engine-plane" aria-label="Permalink to &quot;Engine plane&quot;">​</a></h3><p>The inference engine runs on the host. tnk starts, stops, and queries it with <code>tnk engine</code>.</p><p>The default and production runtime is <code>llama</code> (llama.cpp server). The engine serves an OpenAI-compatible API that sandboxes and services connect over the network.</p><p>Use <code>tnk engine status</code> to check if the engine is running, <code>tnk engine start</code> to launch it, and <code>tnk engine stop</code> to shut it down.</p><h3 id="services-plane" tabindex="-1">Services plane <a class="header-anchor" href="#services-plane" aria-label="Permalink to &quot;Services plane&quot;">​</a></h3><p>A persistent services VM that provides MCP bridge and search tooling for all project sandboxes. Managed with <code>tnk services</code>:</p><ul><li><strong>tnk-services</strong>: MCP bridge and routing on port 18765</li><li><strong>tnk-searxng</strong>: search tooling on port 18766</li></ul><p>This is a dedicated sandbox — not a project workspace — that runs essential MCPs isolated from the host and from per-project sandboxes. Sandboxes reach these services via the runtime environment contract. The services VM runs inside a Lima VM by default. Start, stop, restart, or delete it with <code>tnk services</code>.</p><h3 id="sandbox-plane" tabindex="-1">Sandbox plane <a class="header-anchor" href="#sandbox-plane" aria-label="Permalink to &quot;Sandbox plane&quot;">​</a></h3><p>Per-project sandboxes managed with <code>tnk sandbox</code>. The default backend is Lima — lightweight Linux VMs via the VZ hypervisor.</p><p>Each sandbox mounts only the project directory. Your home folder stays out of scope.</p><p>Sandbox instances are persistent. The same project directory always maps to the same instance name (<code>tnk-{project}</code>). Stop sandboxes between sessions and restart them later. <code>tnk sandbox delete</code> is the only command that removes them.</p><h2 id="why-sandbox" tabindex="-1">Why sandbox <a class="header-anchor" href="#why-sandbox" aria-label="Permalink to &quot;Why sandbox&quot;">​</a></h2><p>Running an AI agent on the host means it executes package installers, shell commands, and network requests with full filesystem access. A compromised dependency or a prompt-induced attack reaches your credentials, keys, and system files.</p><p>tnk keeps agent execution inside isolated sandboxes backed by Lima VMs by default. Each sandbox mounts only the project directory. Your home folder stays out of scope.</p><p>Sandboxes give you:</p><ul><li>filesystem boundaries: project files only, no <code>$HOME</code></li><li>process isolation: agent tools run in a separate environment</li><li>deterministic teardown: <code>tnk shutdown</code> stops every managed component cleanly</li></ul><h2 id="mount-model" tabindex="-1">Mount model <a class="header-anchor" href="#mount-model" aria-label="Permalink to &quot;Mount model&quot;">​</a></h2><p>tnk maps your working directory to the sandbox&#39;s <code>/workspace</code> path.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/code/homepage → tnk-homepage sandbox → /workspace</span></span>
<span class="line"><span>~/code/tnk    → tnk-tnk sandbox    → /workspace</span></span></code></pre></div><p>Only project files appear inside the sandbox. Nothing from outside <code>workspace_root</code> mounts by default. If you need files from another location, mount them explicitly.</p><h2 id="runtime-environment-contract" tabindex="-1">Runtime environment contract <a class="header-anchor" href="#runtime-environment-contract" aria-label="Permalink to &quot;Runtime environment contract&quot;">​</a></h2><p>tnk injects environment variables into every sandbox session. Agents read these to find the services they need:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Points to</th></tr></thead><tbody><tr><td><code>TNK_INFERENCE_URL</code></td><td>Engine inference API</td></tr><tr><td><code>TNK_OPENAI_URL</code></td><td>OpenAI-compatible endpoint</td></tr><tr><td><code>TNK_MCP_BRIDGE_URL</code></td><td>MCP bridge service</td></tr><tr><td><code>TNK_SEARXNG_URL</code></td><td>Search engine</td></tr><tr><td><code>TNK_MODEL_NAME</code></td><td>Current model identifier</td></tr><tr><td><code>TNK_ENGINE_RUNTIME</code></td><td>Active runtime name</td></tr><tr><td><code>TNK_CTX_WINDOW</code></td><td>Context window size</td></tr><tr><td><code>TNK_WORKSPACE_MOUNT</code></td><td>Workspace mount point inside sandbox</td></tr><tr><td><code>TNK_SPECS_REV</code></td><td>Content hash of provision scripts</td></tr></tbody></table><p>Variables are explicit. Agents cannot reach services they are not told about.</p><h2 id="profile-provisioning" tabindex="-1">Profile provisioning <a class="header-anchor" href="#profile-provisioning" aria-label="Permalink to &quot;Profile provisioning&quot;">​</a></h2><p>Profiles configure sandbox environments. The flow:</p><ol><li>tnk checks whether a sandbox instance exists for the current project</li><li>It copies the profile provision script and shared library into the sandbox</li><li>It injects the runtime env contract</li><li>It runs the provision script as the sandbox user <code>tnk</code></li></ol><p>Provision state gets a content hash (<code>TNK_SPECS_REV</code>). If the hash has not changed, tnk skips reinstallation.</p><p>All provision scripts run with <code>set -Eeuo pipefail</code> and <code>umask 077</code>. A trap handler drops tracking tokens on unexpected termination so failed provisions don&#39;t leave stale fingerprints.</p><h3 id="tnk-specs" tabindex="-1">tnk-specs <a class="header-anchor" href="#tnk-specs" aria-label="Permalink to &quot;tnk-specs&quot;">​</a></h3><p><a href="https://github.com/tappunk/tnk-specs" target="_blank" rel="noreferrer">tappunk/tnk-specs</a> hosts sandbox profiles and engine presets. <code>tnk init</code> clones this repository into <code>~/.config/tnk/</code> on your host.</p><p>The repository contains:</p><ul><li><strong>Sandbox manifests</strong>: per-profile YAML definitions under <code>sandbox.d/manifests/</code></li><li><strong>Provision scripts</strong>: setup automation under <code>sandbox.d/provision.d/</code></li><li><strong>Model presets</strong>: engine model INI files under <code>provider.d/</code></li></ul><p>You can point <code>tnk init</code> at a fork or custom specs repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tnk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --git-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/your-org/tnk-specs.git</span></span></code></pre></div><p><code>tnk init --force</code> overwrites the three managed directories (<code>clients/</code>, <code>sandbox.d/</code>, <code>provider.d/</code>) with fresh content from upstream. It leaves <code>tnk.toml</code> and other user files intact.</p><p>Profiles encode resource requirements (CPUs, memory), security posture (network policy), and provisioning steps. Resource values come from the manifest YAML; Lima falls back to 4 CPUs and 4GiB when the manifest omits <code>resources</code>.</p><h3 id="model-presets" tabindex="-1">Model presets <a class="header-anchor" href="#model-presets" aria-label="Permalink to &quot;Model presets&quot;">​</a></h3><p>Model presets live in <code>provider.d/</code> and define which model file and extra flags the inference engine uses. Each preset is an INI file. Presets get updated when you run <code>tnk init</code> against a newer tnk-specs revision.</p><p>The <code>llama</code> runtime uses GGUF models. The preset controls model selection, context size, GPU offload, and threading parameters. The default preset (<code>llama-default</code>) ships with Qwen3.5-9B.</p><h2 id="engine-design" tabindex="-1">Engine design <a class="header-anchor" href="#engine-design" aria-label="Permalink to &quot;Engine design&quot;">​</a></h2><p>tnk ships with <code>llama</code> (llama.cpp server) as the default inference runtime. GGUF provides broad model availability across HuggingFace and other model repositories.</p><h2 id="deferred-network-isolation" tabindex="-1">Deferred network isolation <a class="header-anchor" href="#deferred-network-isolation" aria-label="Permalink to &quot;Deferred network isolation&quot;">​</a></h2><p>Restricted-profile sandboxes receive network access during provisioning so provision scripts can download packages, then tnk cuts the network after provisioning completes.</p><h2 id="audit-logs" tabindex="-1">Audit logs <a class="header-anchor" href="#audit-logs" aria-label="Permalink to &quot;Audit logs&quot;">​</a></h2><p>Every <code>sandbox start</code> and <code>sandbox shell</code> session can record an audit trail with <code>--audit-log PATH</code>. Each entry is NDJSON and includes:</p><ul><li>session start and exit timestamps</li><li>command argv (for non-TTY sessions)</li><li>TTY mode flag</li><li>runtime env summary</li></ul><p>Audit logs stay local.</p><hr><p><strong>See also:</strong> <a href="/tnk/sandbox">Sandbox</a> · <a href="/tnk/security">Security</a> · <a href="/tnk/profiles">Profiles</a></p>`,54)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
